    jellyfin-ffmpeg
    transmission_4-gtk
  ];

  # Disable MCP servers that are unreachable without VPN.
  home-manager.users.${username}.programs.mcp = {
    enableAtlassian = false;
    enableGcloud = false;
    enableGrafana = false;
    enableTempo = false;
  };

  # Configure Docker
  virtualisation.docker = {
    daemon.settings = {
      # Enable CDI for GPU access (modern approach, replaces nvidia-docker)
      features = {
        cdi = true;
      };
